import React, { useRef, useState } from 'react';

interface FileUploadProps {
  onFileSelected: (file: File) => void;
  selectedFile: File | null;
  setSelectedFile: (file: File | null) => void;
}

const FileUpload: React.FC<FileUploadProps> = ({ onFileSelected, selectedFile, setSelectedFile }) => {
  const fileInputRef = useRef<HTMLInputElement>(null);
  const [dragActive, setDragActive] = useState(false);

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files[0]) {
      onFileSelected(e.target.files[0]);
    }
  };

  const handleBoxClick = () => {
    fileInputRef.current?.click();
  };

  const handleDragOver = (e: React.DragEvent<HTMLDivElement>) => {
    e.preventDefault();
    e.stopPropagation();
    setDragActive(true);
  };
  const handleDragLeave = (e: React.DragEvent<HTMLDivElement>) => {
    e.preventDefault();
    e.stopPropagation();
    setDragActive(false);
  };
  const handleDrop = (e: React.DragEvent<HTMLDivElement>) => {
    e.preventDefault();
    e.stopPropagation();
    setDragActive(false);
    if (e.dataTransfer.files && e.dataTransfer.files[0]) {
      onFileSelected(e.dataTransfer.files[0]);
    }
  };

  return (
    <>
      {!selectedFile && (
        <div
          className={`w-full flex flex-col items-center justify-center border-2 border-dashed rounded-xl px-6 py-10 cursor-pointer transition-colors ${dragActive ? 'border-accent bg-slate-50' : 'border-slate-300 bg-white dark:bg-neutral-900'} hover:border-accent focus-visible:border-accent outline-none`}
          tabIndex={0}
          onClick={handleBoxClick}
          onKeyDown={e => (e.key === 'Enter' || e.key === ' ') && handleBoxClick()}
          onDragOver={handleDragOver}
          onDragLeave={handleDragLeave}
          onDrop={handleDrop}
          aria-label="File upload area"
        >
          <input
            type="file"
            accept=".pdf,.doc,.docx,.txt,application/pdf,application/vnd.openxmlformats-officedocument.wordprocessingml.document,application/msword,text/plain"
            className="hidden"
            ref={fileInputRef}
            onChange={handleFileChange}
            tabIndex={-1}
          />
          <span className="text-4xl text-accent mb-2">📤</span>
          <span className="text-sm text-slate-700 dark:text-slate-200 font-medium mb-1">Drop your file here, or click to browse</span>
          <span className="text-xs text-slate-400">PDF, DOCX, or TXT</span>
        </div>
      )}
      {selectedFile && (
        <div className="w-full flex items-center gap-2 mt-2 mb-2">
          <span className="inline-flex items-center px-3 py-1 rounded-full bg-slate-100 dark:bg-neutral-800 border border-slate-200 text-xs text-slate-700 dark:text-slate-200 font-medium">
            {selectedFile.name} <span className="mx-1 text-slate-400">({(selectedFile.size / 1024).toFixed(1)} KB)</span>
            <button
              type="button"
              className="ml-2 text-slate-400 hover:text-accent focus-visible:text-accent transition-colors outline-none"
              aria-label="Remove file"
              onClick={() => setSelectedFile(null)}
            >
              &times;
            </button>
          </span>
        </div>
      )}
    </>
  );
};

export default FileUpload;
